searchData={"items":[{"type":"module","title":"ecsalt","doc":"Entity Component System","ref":"ecsalt.html"},{"type":"type","title":"ecsalt.component/0","doc":"","ref":"ecsalt.html#t:component/0"},{"type":"type","title":"ecsalt.entity/0","doc":"","ref":"ecsalt.html#t:entity/0"},{"type":"opaque","title":"ecsalt.world/0","doc":"","ref":"ecsalt.html#t:world/0"},{"type":"function","title":"ecsalt.delete/1","doc":"Stop the ECS and delete the ETS tables","ref":"ecsalt.html#delete/1"},{"type":"function","title":"ecsalt.new/0","doc":"Start the ECS with ETS tables set to public, return them in an opaque\nworld() type to the caller","ref":"ecsalt.html#new/0"},{"type":"function","title":"ecsalt.proc/2","doc":"For every registered system, trigger the proc callback with some extra data\nspecified by Data and gather results.","ref":"ecsalt.html#proc/2"},{"type":"function","title":"ecsalt.to_map/1","doc":"Convert the component list for a given entity ID to a map.\nWarning: this can potentially create an unbounded number of\natoms!","ref":"ecsalt.html#to_map/1"},{"type":"module","title":"ecsalt_component","doc":"Put, remove, and query named data on entities.","ref":"ecsalt_component.html"},{"type":"type","title":"ecsalt_component.component/0","doc":"","ref":"ecsalt_component.html#t:component/0"},{"type":"type","title":"ecsalt_component.entity/0","doc":"","ref":"ecsalt_component.html#t:entity/0"},{"type":"type","title":"ecsalt_component.id/0","doc":"","ref":"ecsalt_component.html#t:id/0"},{"type":"opaque","title":"ecsalt_component.world/0","doc":"","ref":"ecsalt_component.html#t:world/0"},{"type":"function","title":"ecsalt_component.fold/4","doc":"Fold a function over all entities matching a given set of components,\naccumulating a result.","ref":"ecsalt_component.html#fold/4"},{"type":"function","title":"ecsalt_component.foreach/3","doc":"For each entity with the specified Component, apply fun(EntityID, Values).","ref":"ecsalt_component.html#foreach/3"},{"type":"function","title":"ecsalt_component.match/2","doc":"Return all entities matching a given set of components. Returns empty list if\nthere are no matches.","ref":"ecsalt_component.html#match/2"},{"type":"function","title":"ecsalt_component.put/3","doc":"Associate a component defined as the tuple {key,value} with an entity. If the\ncomponent already exists, it will be replaced with the new value. Returns the\nopaque world() type.","ref":"ecsalt_component.html#put/3"},{"type":"function","title":"ecsalt_component.remove/3","doc":"Remove a component from a given entity. This function will always succeed even\nif the component does not exist.","ref":"ecsalt_component.html#remove/3"},{"type":"function","title":"ecsalt_component.update/4","doc":"Update a component's value by applying a function to it. The component\nmust already exist on the entity.","ref":"ecsalt_component.html#update/4"},{"type":"module","title":"ecsalt_entity","doc":"","ref":"ecsalt_entity.html"},{"type":"type","title":"ecsalt_entity.component/0","doc":"","ref":"ecsalt_entity.html#t:component/0"},{"type":"type","title":"ecsalt_entity.entity/0","doc":"","ref":"ecsalt_entity.html#t:entity/0"},{"type":"type","title":"ecsalt_entity.id/0","doc":"","ref":"ecsalt_entity.html#t:id/0"},{"type":"opaque","title":"ecsalt_entity.world/0","doc":"","ref":"ecsalt_entity.html#t:world/0"},{"type":"function","title":"ecsalt_entity.delete/2","doc":"Delete a given entity from the entity table","ref":"ecsalt_entity.html#delete/2"},{"type":"function","title":"ecsalt_entity.get/2","doc":"Get an entity and all attached components, otherwise false","ref":"ecsalt_entity.html#get/2"},{"type":"function","title":"ecsalt_entity.list/1","doc":"List all entities in #world{}","ref":"ecsalt_entity.html#list/1"},{"type":"function","title":"ecsalt_entity.new/2","doc":"Insert a new entity into the entity table, identified by EntityID","ref":"ecsalt_entity.html#new/2"},{"type":"module","title":"ecsalt_system","doc":"Register, list, and unregister callbacks","ref":"ecsalt_system.html"},{"type":"type","title":"ecsalt_system.component/0","doc":"","ref":"ecsalt_system.html#t:component/0"},{"type":"type","title":"ecsalt_system.entity/0","doc":"","ref":"ecsalt_system.html#t:entity/0"},{"type":"type","title":"ecsalt_system.system/0","doc":"","ref":"ecsalt_system.html#t:system/0"},{"type":"opaque","title":"ecsalt_system.world/0","doc":"","ref":"ecsalt_system.html#t:world/0"},{"type":"function","title":"ecsalt_system.list/1","doc":"List all registered systems and their relative priority","ref":"ecsalt_system.html#list/1"},{"type":"function","title":"ecsalt_system.register/2","doc":"Register a callback of the form {module, fun, 2} or fun(M,N) that will accept\nData as the first argument and the World reference as the second argument.","ref":"ecsalt_system.html#register/2"},{"type":"function","title":"ecsalt_system.register/3","doc":"The same as register/2, but priority may also be specified. Negative values are\nhigher priority.","ref":"ecsalt_system.html#register/3"},{"type":"function","title":"ecsalt_system.unregister/2","doc":"Remove a system from the ECS world.","ref":"ecsalt_system.html#unregister/2"}],"proglang":"erlang","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.39.1"}}